create table dirkspzm32.isi_res_mag_cfg (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(6, 0) not null enable,
    res_id               number(*, 0) not null enable,
    created_date         date not null enable,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0),
    usage                varchar2(10 char) not null enable,
    enabled              varchar2(1 char) default 'T' not null enable,
    status               varchar2(10 char) not null enable,
    mag_params           varchar2(4000 char),
    menge_max            number(*, 3),
    menge_min            number(*, 3),
    artikel_id           number(*, 0),
    zeichnung            varchar2(255 char),
    zeichnung_index      varchar2(10 char),
    charge               varchar2(40 char),
    menge_ist            number(*, 3),
    mag_type             varchar2(10 char),
    modul_bearbeiter     varchar2(3 char),
    lte_name             varchar2(22 char),
    lhm_name             varchar2(50 char)
);

alter table dirkspzm32.isi_res_mag_cfg
    add constraint pk_isi_res_mag_cfg
        primary key ( res_id,
                      firma_nr,
                      sid )
            using index enable;


